1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	const BLOCK_OF_3_PRICE = 60;
16	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	const CURSE_SURCHARGE_RATE = 0.5;
20	
21	function quotePremium(items: Item[]): number {
22	  const countsByType: Record<string, number> = {};
23	  for (const item of items) {
24	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
25	  }
26	  let policyBase = 0;
27	  for (const [type, count] of Object.entries(countsByType)) {
28	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
29	      policyBase += BLOCK_OF_3_PRICE;
30	    } else {
31	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
32	    }
33	  }
34	  let itemSurcharges = 0;
35	  for (const item of items) {
36	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
37	      itemSurcharges +=
38	        HIGH_ENCHANTMENT_SURCHARGE_RATE * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
39	    }
40	    if (item.cursed) {
41	      itemSurcharges +=
42	        CURSE_SURCHARGE_RATE * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
43	    }
44	  }
45	  const firstInsurance = policyBase / 10;
46	  return Math.ceil(policyBase + itemSurcharges + firstInsurance) + PROCESSING_FEE;
47	}
48	
49	export function processScenario(scenario: unknown): unknown {
50	  const { steps } = scenario as Scenario;
51	  const results = steps.map((step) => ({
52	    premium: quotePremium(step.items ?? []),
53	  }));
54	  return { results };
55	}
